mapper.select:
SELECT trip_place_id
FROM trip_place
WHERE place_name = #{placeName}
  AND address    = #{address}
  AND ROWNUM = 1

SELECT trip_place_id AS placeId, member_id AS memberId, api_place_id AS apiContentId, place_name AS placeName, address, latitude, longitude, category_name AS category, place_url AS imageUrl, CASE WHEN member_id IS NOT NULL THEN 1 ELSE 0 END AS isCustom FROM trip_place WHERE place_name = #{placeName} AND address = #{address}
AND member_id = #{memberId}
AND member_id IS NULL
AND ROWNUM = 1

mapper.delete:
DELETE FROM itinerary_image
WHERE item_id IN (
    SELECT item_id
    FROM itinerary_item
    WHERE trip_place_id = #{placeId}
)

DELETE FROM trip_place
WHERE trip_place_id = #{placeId}
  AND member_id     = #{memberId}
